import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.Bb5YUzRP.js";var i=JSON.parse(`{"title":"Introduction","description":"Introduction to Nodalite, a runtime-agnostic TypeScript API framework that runs unmodified on Node.js, Bun, Deno, Cloudflare Workers, and AWS Lambda. ","frontmatter":{"description":"Introduction to Nodalite, a runtime-agnostic TypeScript API framework that runs unmodified on Node.js, Bun, Deno, Cloudflare Workers, and AWS Lambda. "},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1784063781000}`),a={name:`guide/index.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><p><strong>Nodalite</strong> is a small, runtime-agnostic TypeScript API framework. The same <code>App</code> instance runs unmodified on:</p><ul><li><strong>Node.js</strong> (18+) — via <code>@nodalite/adapter-node</code></li><li><strong>AWS Lambda</strong> — via <code>@nodalite/adapter-lambda</code></li><li><strong>Cloudflare Workers</strong> — via <code>@nodalite/adapter-edge</code></li><li><strong>Bun</strong> and <strong>Deno</strong> — directly, no adapter needed</li></ul><h2 id="what-makes-it-different" tabindex="-1">What makes it different? <a class="header-anchor" href="#what-makes-it-different" aria-label="Permalink to “What makes it different?”">​</a></h2><table tabindex="0"><thead><tr><th>Framework</th><th>Runtimes</th><th>Serverless-native</th><th>Built-in security</th><th>Background jobs</th><th>ML inference</th></tr></thead><tbody><tr><td>Express 5</td><td>Node only</td><td>Bolt-on</td><td>None</td><td>None</td><td>None</td></tr><tr><td>Fastify 5</td><td>Node only</td><td>Bolt-on</td><td>Plugins</td><td>None</td><td>None</td></tr><tr><td>NestJS</td><td>Node only</td><td>Poor cold starts</td><td>Guards/interceptors</td><td><code>@nestjs/schedule</code></td><td>None</td></tr><tr><td>Hono</td><td>Node/Bun/Deno/Workers/Lambda</td><td>Yes</td><td>Middleware ecosystem</td><td>None</td><td>None</td></tr><tr><td>Elysia</td><td>Bun-first</td><td>Bun only</td><td>Plugins</td><td>None</td><td>None</td></tr><tr><td><strong>Nodalite</strong></td><td>Node/Bun/Deno/Workers/Lambda</td><td>Yes (first-class)</td><td>Built in</td><td>Yes</td><td>Yes</td></tr></tbody></table><h3 id="genuinely-unmet-needs" tabindex="-1">Genuinely unmet needs <a class="header-anchor" href="#genuinely-unmet-needs" aria-label="Permalink to “Genuinely unmet needs”">​</a></h3><ol><li><p><strong>Background threads alongside your API</strong> — <code>@nodalite/workers</code>&#39; <code>runDetached()</code> runs a supervised <code>worker_thread</code> (bot, poller, watcher) in the same process, with automatic crash recovery. See <a href="/guides/background-threads">Background Threads</a>.</p></li><li><p><strong>Lightweight ML inference on serverless</strong> — <code>@nodalite/ml</code>&#39;s <code>Model</code> class disk-caches model bytes across cold starts, deduplicates concurrent load requests, and is engine-agnostic so it doesn&#39;t force a heavy native dependency on you. See <a href="/guides/ml-inference">ML Inference</a>.</p></li></ol><p>Everything else — routing, middleware, validation, auth, rate limiting — is a well-executed implementation of table-stakes features, built on the standard Fetch API so the exact same code genuinely runs everywhere.</p><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to “Design principles”">​</a></h2><ul><li><strong>Fetch API foundation</strong> — <code>Request</code>/<code>Response</code>/<code>Headers</code>/<code>ReadableStream</code> are the only primitives. No runtime-specific shapes.</li><li><strong>Zero dependencies in core</strong> — <code>@nodalite/core</code> relies on nothing but the JS runtime. This keeps bundles small and supply-chain risk minimal.</li><li><strong>Independent versioning</strong> — each package ships independently. Adapter fixes don&#39;t bump core. ML&#39;s heavy native deps stay optional.</li><li><strong>Honest about limits</strong> — <code>runDetached()</code> can&#39;t work on FaaS, and the docs say so explicitly. No marketing over truth.</li></ul>`,10)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};